}

void draw() {
background(255);


// 绘制树干
stroke(139, 69, 19); // 棕色
strokeWeight(5);
line(targetX, targetY, targetX, targetY + targetSize1.2);

// 绘制树叶
noStroke();
fill(34, 139, 34); // 绿色
ellipse(targetX, targetY - targetSize1.2, targetSize1.3, targetSize1.3);
ellipse(targetX - targetSize/2, targetY - targetSize/2, targetSize1.3, targetSize1.3);
ellipse(targetX + targetSize/2, targetY - targetSize/2, targetSize1.3, targetSize1.3);
ellipse(targetX, targetY - targetSize/2, targetSize1.3, targetSize1.3);

// 更新并绘制石头
stone.update();
stone.draw();

// 显示得分
textAlign(RIGHT, TOP);
