isHit = true;
score++;
resetStone();
resetTarget();
}

if (stone.x>width+50||stone.x<0||stone.y<0||stone.y>height){
resetStone();
}
}

long mousePressedTime = 0;

void mousePressed() {
if (!stone.isFired) {
mousePressedTime = millis();
}
}

void mouseReleased() {
if (!stone.isFired) {
float time = millis() - mousePressedTime;
time = constrain(time, 0, 1000);
float power = map(time, 0, 1000, 0, 20);
float angle = atan2(mouseY - stone.y, mouseX - stone.x);
stone.fire(power, angle);

// 重置蓄能值
charge = 0;
}
}

void keyPressed() {
if (keyCode == UP && charge < maxCharge) {
charge += 10;
}
}

下面是Stone脚本：
class Stone {
float size;
float x, y;
float speed;
float angle;
PVector velocity;
PVector acceleration;
float gravity;

boolean isFired;

Stone(float size, float x, float y, float gravity) {
this.size = size;
this.x = x;
this.y = y;
this.gravity = gravity;

isFired = false;
velocity = new PVector(0, 0);
acceleration = new PVector(0, 0);
}

void applyForce(PVector force) {
PVector f = PVector.div(force, size);
acceleration.add(f);
}

void update() {
if (isFired) {
PVector force = new PVector(0, gravity * size);
applyForce(force);

velocity.add(acceleration);
x += velocity.x;
y += velocity.y;

if (y > height - size/2) {
y = height - size/2;
velocity.y *= -0.9;
angle = PI - angle;
}

acceleration.mult(0); // 清空加速度
}
}

void draw() {
fill(0);
ellipse(x, y, size, size);
}

void fire(float power, float angle) {
if (!isFired) {
speed = power;
this.angle = angle;
velocity = PVector.fromAngle(angle);
velocity.mult(speed);
isFired = true;
}
}

boolean checkCollision(float targetX, float targetY, float targetSize) {
float distance = dist(x, y, targetX, targetY);
float radiusSum = size / 2 + targetSize / 2;
return distance <= radiusSum;
}
}

