我们将添加一个静止的石头 `stationaryStone` 在场景中，然后当动态的石头 `stone` 发射并且撞到 `stationaryStone` 时，它们将根据动量守恒和能量守恒定律发生碰撞。发生碰撞后，`stationaryStone` 将朝树的方向飞去，如果命中将增加分数。

首先，需要增加静止小球的定义：

Main脚本：

```java
// ...其他变量声明
Stone stationaryStone;

void setup() {
  size(800, 600);
  resetStone();
  resetTarget();
  // 初始化静止的石头位置
  stationaryStone = new Stone(20, width / 4, height / 2, 0.3);
}

// ...setup、draw和其他函数...

void draw() {
  // ...背景、树的绘制、石头的更新和绘制、得分的显示...

  // 绘制静止的石头
  stationaryStone.draw();

  // 处理动态石头和静止石头的碰撞
  if (stone.isFired && !stationaryStone.isFired 
      && stone.checkCollision(stationaryStone.x, stationaryStone.y, stationaryStone.size)) {
    // 处理碰撞
    handleCollision();
  }

  // ...其余的draw函数代码
}

void handleCollision() {
  // 根据动量守恒定律计算两个石头的速度
  float m1 = stone.size; // 假设质量与大小成正比
  float m2 = stationaryStone.size;
  PVector v1Initial = stone.velocity.copy();
  PVector v2Initial = new PVector(0, 0); // 初始时静止石头的速度为0

  // 计算碰撞后的速度
  PVector v1Final = new PVector((m1 - m2) / (m1 + m2) * v1Initial.x, v1Initial.y);
  PVector v2Final = new PVector((2 * m1) / (m1 + m2) * v1Initial.x, v1Initial.y);

  // 将计算后的速度设置为石头的新速度
  stone.velocity.set(v1Final);
  stationaryStone.velocity.set(v2Final);
  stationaryStone.isFired = true; // 将静止石头设置为运动状态

  // 重置动态石头
  resetStone();
}

// ...其余的Main脚本代码
```

