void transferMomentum(Stone stone1, Stone stone2) {
  // 根据动量守恒定理计算并传递动量

  // 假设质量和大小成正比
  float m1 = stone1.size;
  float m2 = stone2.size;
  PVector v1Initial = stone1.velocity.copy();

  // 使用一维弹性碰撞公式计算
  PVector v1Final = new PVector((m1 - m2) / (m1 + m2) * v1Initial.x, v1Initial.y);
  PVector v2Final = new PVector((2 * m1) / (m1 + m2) * v1Initial.x, v1Initial.y);

  stone1.isFired = false; // 停止第一个stone的移动
  stone2.fire(v2Final.mag(), v2Final.heading()); // 启动stationary stone的移动
}
