```java
class Stone {
    float size;
    float x, y;
    PVector velocity;
    float gravity;
    boolean isFired;

    Stone(float size, float x, float y, float gravity) {
        this.size = size;
        this.x = x;
        this.y = y;
        this.gravity = gravity;
        velocity = new PVector(0, 0);
        isFired = false;
    }

    void update() {
        if (isFired) {
            velocity.y += gravity;
            x += velocity.x;
            y += velocity.y;
            if (y > height - size / 2) {
                y = height - size / 2;
                velocity.y *= -0.9; // 碰地面后的反弹效果
            }
        }
    }

    void display() {
        fill(127);
        stroke(0);
        ellipse(x, y, size, size);
    }

    void fire(float speed, float angle) {
        if (!isFired) {
            velocity = PVector.fromAngle(angle).mult(speed);
            isFired = true;
        }
    }

    void stop() {
        isFired = false;
        velocity = new PVector(0, 0);
    }

    boolean checkCollision(Stone other) {
        if (isFired && !other.isFired && dist(x, y, other.x, other.y) <= (size + other.size) / 2) {
            return true;
        }
        return false;
    }
}
